155→export function createStair(startPoint, width = STAIR_WIDTH, numberOfRisers = STAIR_RISERS, riserHeight = STAIR_RISER_HEIGHT, treadDepth = STAIR_TREAD_DEPTH, direction = { angle: 0 }, floorRelation = {}, options = {}) {
156→  return {
157→    id: generateId('stair'),
158→    startPoint: { x: startPoint.x, y: startPoint.y },
159→    width,
160→    numberOfRisers,
161→    riserHeight,
162→    treadDepth,
163→    direction: {
164→      angle: direction?.angle ?? 0,
165→    },
166→    floorRelation: {
167→      fromFloorId: floorRelation.fromFloorId ?? null,
168→      toFloorId: floorRelation.toFloorId ?? null,
169→    },
170→    startLandingAttachment: options.startLandingAttachment ?? null,
171→    endLandingAttachment: options.endLandingAttachment ?? null,
172→  };
