187→export function createSectionCut(startPoint, endPoint, options = {}) {
188→  return {
189→    id: generateId('section'),
190→    startPoint: { x: startPoint.x, y: startPoint.y },
191→    endPoint: { x: endPoint.x, y: endPoint.y },
