198→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
199→  const area = polygonArea(points);
200→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
201→  return {
202→    id: generateId('room'),
203→    name,
204→    points: points.map(p => ({ x: p.x, y: p.y })),
205→    labelPosition: { ...centroid },
206→    color,
207→    area,
208→  };
209→}
